function solve(code, businessLine, isActive) {
    const validBusinessLines = new Set(["electronics", "grocery", "pharmacy", "restaurant"]);
    const businessLineOrder = { "electronics": 0, "grocery": 1, "pharmacy": 2, "restaurant": 3 };

    const isValidCoupon = (i) => {
        if (!isActive[i]) return false;
        if (!validBusinessLines.has(businessLine[i])) return false;
        if (!code[i] || code[i].length === 0) return false;
        const validChars = /^[a-zA-Z0-9_]+$/;
        if (!validChars.test(code[i])) return false;
        return true;
    };

    const validCoupons = [];
    for (let i = 0; i < code.length; i++) {
        if (isValidCoupon(i)) {
            validCoupons.push({
                code: code[i],
                businessLine: businessLine[i]
            });
        }
    }

    validCoupons.sort((a, b) => {
        if (businessLineOrder[a.businessLine] !== businessLineOrder[b.businessLine]) {
            return businessLineOrder[a.businessLine] - businessLineOrder[b.businessLine];
        } else {
            return a.code.localeCompare(b.code);
        }
    });

    return validCoupons.map(coupon => coupon.code);
}

